var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......많군.","JPN":"……多いな。","ENG":"That's a lot.","TWN":"……真多啊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그냥 많은 정도가 아닌데요?","JPN":"これは普通に多いとかのレベルではないのでは？","ENG":"That's more than a lot.","TWN":"不只是真多而已吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 수를 봐서는......","JPN":"このおびただしい数は……","ENG":"By the looks of it,","TWN":"看這數量……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"도시에 있던 사람들 전부 침식체로 변이했다고 봐도 될 정도로군요.","JPN":"街にいた全員が、侵食体に変異してしまったとみるのが妥当かもしれませんね。","ENG":"it'd be safe to say that all the residents of this city have turned into C.O.s.","TWN":"可以說整座城市裡的人都變異成了侵蝕體呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......끔찍한 상상이군.","JPN":"……想像しただけでゾッとするが、","ENG":"That's terrible.","TWN":"……這真是個可怕的想像啊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 도시에 생존자가 없었던 걸 보면 근거 없는 말은 아닐지도 모르겠어.","JPN":"街に生存者はいなかったし、可能性がないとは言えんな。","ENG":"But you may be right, considering there were zero survivors in the city.","TWN":"但我們在城市裡沒有看到倖存者，說不定也不是毫無根據的話。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체는 죽인......! 아니, 박살낸다!!","JPN":"侵食体は殺……！　いや、壊してやる！！","ENG":"Corrupted Objects, I must ki—I mean, smash!","TWN":"侵蝕體，殺……！不，粉碎！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......펄펄 날아다니는군.","JPN":"……水を得た魚のようだ。","ENG":"She's like a train with no brakes.","TWN":"……真是輕如飛燕呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"오르카 덕분에 고생이 줄었어.","JPN":"オルカのおかげで、だいぶ手間が省けたよ。","ENG":"Things are a lot much easier for us thanks to her.","TWN":"多虧了奧爾卡，我們輕鬆了不少。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 여기에 오래 머무르는 건 별로 좋은 생각이 아니겠지.","JPN":"けど、ここに長居するのは得策じゃないな。","ENG":"But it can't be a good idea to stay here any longer than necessary.","TWN":"但在這裡久留也不是什麼好主意。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"빨리 움직이자.","JPN":"早く動こう。","ENG":"Let's get moving.","TWN":"趕快行動吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이터니움을 실은 트럭은 어디에 있지?","JPN":"エタニウムを積んだトラックはどこだ？","ENG":"Where's the Eternium-loaded truck?","TWN":"裝著永恆之金的卡車在哪？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 트럭이 보이질 않네요.","JPN":"そういえば、トラックが見当たりませんね。","ENG":"You're right. I don't see it anywhere.","TWN":"說到這個，我沒看到卡車呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조금 전까지만 해도 이 근처에 있었는데......","JPN":"ついさっきまでこの近くにあったのに。","ENG":"It was right over here just a while ago.","TWN":"剛才還在這附近……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아앗! 어, 어딜 가는 거에요, 당신!!","JPN":"ああ！　あなた、ど、どこに行くんです！！","ENG":"Hey! W-where do you think you're going?","TWN":"啊啊！你、你要去哪裡啊，你！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MERCHANT_EXTRA_NULL_NULL","text":{"KOREA":"시끄러웟!!","JPN":"やかましいっ！！","ENG":"Oh, shut it!","TWN":"吵死了！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"MERCHANT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};